import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Card, Button, Row, Col, Spinner, Alert, Badge, Modal } from 'react-bootstrap';
import SelectorMetodoPago from './SelectorMetodoPago';
import { API_URL, API_PREFIX, STANDARD_HEADERS, vaciarCarrito } from '../servicios/api.jsx';

const Pagos = ({ usuario, onCompletePurchase, onCancel, directCheckout = false }) => {
  const [loading, setLoading] = useState(true);
  const [processingPayment, setProcessingPayment] = useState(false);
  const [error, setError] = useState(null);
  const [cart, setCart] = useState([]);
  const [paymentMethod, setPaymentMethod] = useState(null);
  const [discount, setDiscount] = useState(null);
  const [retryCount, setRetryCount] = useState(0);
  const [offlineMode, setOfflineMode] = useState(!navigator.onLine);

  const [currentStep, setCurrentStep] = useState(directCheckout ? 2 : 1);

  const [subtotal, setSubtotal] = useState(0);
  const [discountAmount, setDiscountAmount] = useState(0);
  const [total, setTotal] = useState(0);

  const [showClientModal, setShowClientModal] = useState(false);
  const [clientInfo, setClientInfo] = useState({
    nombre: '',
    documento: '',
    telefono: '',
    direccion: ''
  });

  const [receipt, setReceipt] = useState(null);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [paymentProcessed, setPaymentProcessed] = useState(false);
  
  const [isEmergencyMode, setIsEmergencyMode] = useState(false);

  useEffect(() => {
    const handleOnline = () => setOfflineMode(false);
    const handleOffline = () => setOfflineMode(true);
    
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    loadCartItems();
  }, []);

  useEffect(() => {
    const cartSubtotal = cart.reduce((sum, item) => {
      return sum + (item.productos?.precio || item.precio || 0) * item.cantidad;
    }, 0);

    setSubtotal(cartSubtotal);

    let discountValue = 0;
    if (discount) {
      if (discount.tipo === 'porcentaje') {
        discountValue = cartSubtotal * (discount.valor / 100);
      } else if (discount.tipo === 'monto') {
        discountValue = discount.valor;
      }
    }

    setDiscountAmount(discountValue);
    setTotal(cartSubtotal - discountValue);
  }, [cart, discount]);

  const loadCartItems = async () => {
    try {
      setLoading(true);
      
      try {
        if (usuario?.id) {
          const userCartResponse = await fetch(`${API_URL}${API_PREFIX}carrito/usuario/${usuario.id}`, {
            headers: {
              'Accept': 'application/json',
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${usuario.token || 'no-token'}`
            },
            signal: AbortSignal.timeout(8000)
          });
          
          if (userCartResponse.ok) {
            const userData = await userCartResponse.json();
            setCart(userData?.items || []);
            setLoading(false);
            return;
          }
        }
      } catch (userCartError) {}

      try {
        const response = await fetch(`${API_URL}${API_PREFIX}carrito`, {
          headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${usuario?.token || 'no-token'}`
          },
          signal: AbortSignal.timeout(8000)
        });

        if (!response.ok) {
          throw new Error(`Error al obtener carrito: ${response.status}`);
        }
        
        const data = await response.json();
        setCart(data?.items || []);
        
        try {
          localStorage.setItem('carritoCache', JSON.stringify(data?.items || []));
        } catch (cacheError) {}
      } catch (generalError) {
        const cachedCart = localStorage.getItem('carritoCache');
        if (cachedCart) {
          try {
            const parsedCart = JSON.parse(cachedCart);
            setCart(parsedCart);
            setIsEmergencyMode(true);
          } catch (cacheError) {
            throw new Error('Error al cargar el carrito');
          }
        } else {
          throw new Error('No se pudo obtener el carrito');
        }
      }
    } catch (err) {
      setError(err.message || 'Error al cargar el carrito');
      setLoading(false);
      setIsEmergencyMode(true);
      
      try {
        const cachedCart = localStorage.getItem('carritoCache');
        if (cachedCart) {
          const parsedCart = JSON.parse(cachedCart);
          setCart(parsedCart);
        }
      } catch (cacheError) {}
    } finally {
      setLoading(false);
    }
  };

  const handleGoToNextStep = () => {
    setCurrentStep(2);
  };

  const handleGoBackToResume = () => {
    setCurrentStep(1);
  };

  const handleSelectPaymentMethod = (method) => {
    setPaymentMethod(method);
  };

  const validatePaymentDetails = () => {
    if (!paymentMethod) return false;

    const details = paymentMethod.details;

    if (paymentMethod.id === 'efectivo') {
      return parseFloat(details.amount) >= total;
    } 
    else if (paymentMethod.id === 'tarjeta') {
      return details.cardDigits && details.cardDigits.length === 4 && details.reference;
    }
    else if (paymentMethod.id === 'transferencia') {
      return details.reference && details.reference.trim() !== '';
    }
    else if (paymentMethod.id === 'credito') {
      return details.clientName && details.clientName.trim() !== '';
    }
    else if (paymentMethod.id === 'mixto') {
      if (!details.mixedPayments || details.mixedPayments.length === 0) return false;
      
      const totalPaid = details.mixedPayments.reduce((sum, payment) => {
        return sum + (parseFloat(payment.amount) || 0);
      }, 0);
      
      return Math.abs(totalPaid - total) <= 0.01;
    }
    
    return true;
  };

  const handleSubmitPayment = () => {
    if (!validatePaymentDetails()) {
      setError('Por favor completa correctamente los detalles del pago');
      return;
    }
    
    setRetryCount(0);
    processPayment();
  };

  const cleanupAfterPayment = async () => {
    try {
      if (navigator.onLine) {
        try {
          const result = await vaciarCarrito();
        } catch (vaciarError) {
          try {
            const response = await fetch(`${API_URL}${API_PREFIX}carrito/vaciar`, {
              method: 'DELETE',
              headers: {
                'Authorization': `Bearer ${usuario?.token || ''}`,
                'Content-Type': 'application/json'
              },
              signal: AbortSignal.timeout(5000)
            });
          } catch (directError) {}
        }
        
        localStorage.removeItem('carritoCache');
        localStorage.removeItem('carritoCacheTimestamp');
      } else {
        localStorage.removeItem('carritoCache');
        localStorage.removeItem('carritoCacheTimestamp');
      }
    } catch (cleanupError) {}
  };

  const processPayment = async () => {
    try {
      setProcessingPayment(true);
      setError(null);

      if (offlineMode) {
        await processOfflinePayment();
        return;
      }

      const ventaData = {
        items: cart.map(item => {
          const productoId = item.productos?.id || item.producto_id || item.id;
          const productoPrecio = item.productos?.precio || item.precio || 0;
          const productoNombre = item.productos?.nombre || item.nombre || 'Producto';

          return {
            producto_id: productoId,
            cantidad: item.cantidad,
            precio: productoPrecio,
            nombre: productoNombre
          };
        }),
        metodoPago: paymentMethod.id,
        detallesPago: paymentMethod.details,
        total: total,
        subtotal: subtotal,
        descuento: discountAmount,
        usuario_id: usuario?.id || null,
        cliente_id: clientInfo?.id || null,
        actualizar_inventario: true,
        vaciar_carrito: true,
        timestamp: Date.now(),
        device_id: localStorage.getItem('deviceId') || 
                  `device_${Math.random().toString(36).substring(2, 10)}`
      };
      
      if (!localStorage.getItem('deviceId')) {
        localStorage.setItem('deviceId', ventaData.device_id);
      }

      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 20000);
        
        const retryDelay = Math.min(1000 * Math.pow(2, retryCount) + Math.random() * 1000, 10000);
        
        const response = await fetch(`${API_URL}${API_PREFIX}ventas`, {
          method: 'POST',
          headers: {
            ...STANDARD_HEADERS,
            'Accept': 'application/json',
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${usuario?.token || 'no-token'}`,
            'X-Device-ID': ventaData.device_id,
            'X-Request-ID': `req_${Date.now()}_${Math.random().toString(36).substring(2, 10)}`,
            'X-Retry-Count': retryCount.toString()
          },
          body: JSON.stringify(ventaData),
          mode: 'cors',
          signal: controller.signal
        });
        
        clearTimeout(timeoutId);
        
        const responseText = await response.text();
        
        if (!responseText || responseText.trim() === '' || 
            responseText.includes('{"error":"{}"}')) {
          await processOfflinePayment();
          return;
        }
        
        let ventaResponse;
        try {
          ventaResponse = JSON.parse(responseText);
        } catch (jsonError) {
          if (response.ok) {
            const reciboBasico = {
              id: `manual_${Date.now()}`,
              fecha: new Date().toISOString(),
              total: total,
              subtotal: subtotal,
              descuento: discountAmount,
              metodoPago: paymentMethod.id,
              detallesPago: paymentMethod.details,
              productos: ventaData.items,
              usuarioNombre: usuario?.nombre || 'Usuario',
              manualCreation: true
            };
            
            await cleanupAfterPayment();
            
            setReceipt(reciboBasico);
            setShowReceiptModal(true);
            setProcessingPayment(false);
            setPaymentProcessed(true);
            return;
          } else {
            throw new Error('La respuesta del servidor no es JSON válido: ' + responseText.substring(0, 100));
          }
        }
        
        if (!ventaResponse) {
          throw new Error('Respuesta vacía del servidor');
        }
        
        if (ventaResponse.error) {
          if (typeof ventaResponse.error === 'string' && 
              ventaResponse.error.includes('inventario insuficiente')) {
            throw new Error('No hay suficiente inventario para alguno de los productos');
          }
          
          throw new Error(ventaResponse.error.toString());
        }
        
        const ventaCompleta = ventaResponse.venta || ventaResponse;
        
        ventaCompleta.productos = ventaResponse.productos || ventaData.items;
        ventaCompleta.metodoPago = paymentMethod.id;
        ventaCompleta.detallesPago = paymentMethod.details;
        ventaCompleta.usuarioNombre = usuario?.nombre || 'Usuario';
        
        await cleanupAfterPayment();
        
        setReceipt(ventaCompleta);
        setShowReceiptModal(true);
        setProcessingPayment(false);
        setPaymentProcessed(true);
        
      } catch (networkError) {
        if (networkError.name === 'AbortError') {}
        
        if (retryCount < 2) {
          const nextRetryDelay = Math.min(1000 * Math.pow(2, retryCount) + Math.random() * 1000, 10000);
          
          setRetryCount(prev => prev + 1);
          setError(`Error de conexión. Reintentando en ${Math.ceil(nextRetryDelay/1000)} segundos...`);
          
          setTimeout(() => {
            processPayment();
          }, nextRetryDelay);
          return;
        }
        
        setError('No se pudo conectar con el servidor. ¿Deseas procesar el pago en modo offline?');
        setProcessingPayment(false);
        setIsEmergencyMode(true);
      }
      
    } catch (err) {
      if (err.message && err.message.includes('inventario insuficiente')) {
        setError('No hay suficiente inventario para completar la compra');
      } else {
        setError(err.message || 'Error al conectar con el servidor');
      }
      
      setProcessingPayment(false);
    }
  };

  const processOfflinePayment = async () => {
    try {
      const emergencyReceipt = {
        id: `offline_${Date.now()}_${Math.random().toString(36).substring(2, 10)}`,
        fecha: new Date().toISOString(),
        total: total,
        subtotal: subtotal,
        descuento: discountAmount,
        metodoPago: paymentMethod.id,
        detallesPago: paymentMethod.details,
        productos: cart.map(item => {
          const productoId = item.productos?.id || item.producto_id || item.id;
          const productoPrecio = item.productos?.precio || item.precio || 0;
          const productoNombre = item.productos?.nombre || item.nombre || 'Producto';

          return {
            producto_id: productoId,
            cantidad: item.cantidad,
            precio: productoPrecio,
            nombre: productoNombre
          };
        }),
        usuarioNombre: usuario?.nombre || 'Usuario',
        offlineMode: true,
        deviceId: localStorage.getItem('deviceId') || 
                 `device_${Math.random().toString(36).substring(2, 10)}`
      };
      
      const ventaData = {
        items: emergencyReceipt.productos,
        metodoPago: paymentMethod.id,
        detallesPago: paymentMethod.details,
        total: total,
        subtotal: subtotal,
        descuento: discountAmount,
        usuario_id: usuario?.id || null,
        cliente_id: clientInfo?.id || null,
        actualizar_inventario: true,
        offlineId: emergencyReceipt.id,
        timestamp: Date.now(),
        deviceId: emergencyReceipt.deviceId
      };
      
      try {
        const pendingPayments = JSON.parse(localStorage.getItem('pendingPayments') || '[]');
        pendingPayments.push({
          timestamp: Date.now(),
          ventaData,
          receipt: emergencyReceipt
        });
        localStorage.setItem('pendingPayments', JSON.stringify(pendingPayments));
      } catch (storageError) {}
      
      localStorage.removeItem('carritoCache');
      localStorage.removeItem('carritoCacheTimestamp');
      
      setReceipt(emergencyReceipt);
      setShowReceiptModal(true);
      setProcessingPayment(false);
      setPaymentProcessed(true);
      
    } catch (offlineError) {
      setError("Error al procesar pago en modo offline: " + offlineError.message);
      setProcessingPayment(false);
    }
  };

  const handleCloseReceipt = () => {
    setShowReceiptModal(false);
    
    if (onCompletePurchase) {
      onCompletePurchase(receipt);
    }
  };

  if (loading || processingPayment) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '300px' }}>
        <Spinner animation="border" variant="primary" />
        <span className="ms-3">
          {loading ? 'Cargando información...' : 'Procesando pago...'}
        </span>
      </div>
    );
  }

  return (
    <div className="payment-process">
      {error && (
        <Alert variant="danger" className="mb-4 d-flex justify-content-between align-items-center">
          <div>
            <i className="fas fa-exclamation-circle me-2"></i>
            {error}
          </div>
          
          {isEmergencyMode && (
            <Button 
              variant="outline-light" 
              size="sm"
              onClick={processOfflinePayment}
            >
              Procesar Offline
            </Button>
          )}
        </Alert>
      )}

      {isEmergencyMode && (
        <Alert variant="warning" className="mb-4">
          <i className="fas fa-exclamation-triangle me-2"></i>
          Usando modo de emergencia. Algunas funciones pueden estar limitadas.
        </Alert>
      )}

      <h4 className="mb-4">
        {directCheckout ? "Pago Rápido" : "Proceso de Pago"}
        {offlineMode && <Badge bg="warning" className="ms-2">Offline</Badge>}
      </h4>
      
      <div className="steps-container mb-4">
        <div className="d-flex justify-content-between">
          <div className={`step-item ${currentStep >= 1 ? 'active' : ''}`}>
            <div className="step-circle">1</div>
            <div className="step-label">Resumen</div>
          </div>
          <div className={`step-connector ${currentStep >= 2 ? 'active' : ''}`}></div>
          <div className={`step-item ${currentStep >= 2 ? 'active' : ''}`}>
            <div className="step-circle">2</div>
            <div className="step-label">Método de pago</div>
          </div>
          <div className={`step-connector ${currentStep >= 3 ? 'active' : ''}`}></div>
          <div className={`step-item ${currentStep >= 3 ? 'active' : ''}`}>
            <div className="step-circle">3</div>
            <div className="step-label">Confirmación</div>
          </div>
        </div>
      </div>

      {currentStep === 1 && (
        <div className="step-content">
          <Card className="border-0 shadow-sm mb-4">
            <Card.Body>
              <h5 className="mb-4">Resumen de compra</h5>
              
              {cart.length === 0 ? (
                <Alert variant="info">
                  El carrito está vacío. Agrega productos para continuar.
                </Alert>
              ) : (
                <>
                  <div className="cart-items mb-4">
                    {cart.map((item, index) => (
                      <div key={index} className="cart-item d-flex align-items-center py-2 border-bottom">
                        <div className="item-image me-3">
                          {item.productos?.imagen ? (
                            <img 
                              src={item.productos.imagen} 
                              alt={item.productos?.nombre} 
                              style={{ width: '50px', height: '50px', objectFit: 'cover' }}
                              loading="lazy"
                            />
                          ) : (
                            <div 
                              className="bg-light d-flex align-items-center justify-content-center" 
                              style={{ width: '50px', height: '50px' }}
                            >
                              <i className="fas fa-box text-muted"></i>
                            </div>
                          )}
                        </div>
                        <div className="item-details flex-grow-1">
                          <div className="item-name fw-bold">{item.productos?.nombre || item.nombre || 'Producto'}</div>
                          <div className="item-meta text-muted small">
                            Cantidad: {item.cantidad} x ${typeof item.productos?.precio === 'number' ? item.productos.precio.toFixed(2) : 
                                            typeof item.precio === 'number' ? item.precio.toFixed(2) : '0.00'}
                          </div>
                        </div>
                        <div className="item-price text-end">
                          ${((item.productos?.precio || item.precio || 0) * item.cantidad).toFixed(2)}
                        </div>
                      </div>
                    ))}
                  </div>
                  
                  <div className="cart-summary">
                    <div className="d-flex justify-content-between mb-2">
                      <span>Subtotal:</span>
                      <span>${subtotal.toFixed(2)}</span>
                    </div>
                    
                    {discount && (
                      <div className="d-flex justify-content-between mb-2 text-success">
                        <span>
                          Descuento {discount.tipo === 'porcentaje' ? `(${discount.valor}%)` : ''}:
                        </span>
                        <span>-${discountAmount.toFixed(2)}</span>
                      </div>
                    )}
                    
                    <div className="d-flex justify-content-between fw-bold fs-5 mt-3">
                      <span>Total:</span>
                      <span>${total.toFixed(2)}</span>
                    </div>
                  </div>
                </>
              )}
            </Card.Body>
            <Card.Footer className="bg-white d-flex justify-content-between border-top">
              <Button 
                variant="outline-secondary" 
                onClick={onCancel}
              >
                <i className="fas fa-arrow-left me-2"></i>
                Volver
              </Button>
              
              <Button 
                variant="primary" 
                onClick={handleGoToNextStep}
                disabled={cart.length === 0}
              >
                Continuar
                <i className="fas fa-arrow-right ms-2"></i>
              </Button>
            </Card.Footer>
          </Card>
        </div>
      )}

      {currentStep === 2 && (
        <div className="step-content">
          {directCheckout && (
            <Card className="border-0 shadow-sm mb-4">
              <Card.Body>
                <div className="d-flex justify-content-between align-items-center mb-3">
                  <h5 className="mb-0">Resumen</h5>
                  <Button 
                    variant="link" 
                    className="p-0" 
                    onClick={handleGoBackToResume}
                  >
                    Ver detalle
                  </Button>
                </div>
                
                <div className="d-flex justify-content-between align-items-center mb-2">
                  <span>{cart.length} producto(s)</span>
                  <span className="fw-bold">${total.toFixed(2)}</span>
                </div>
                
                <div className="compact-items small mb-3">
                  {cart.slice(0, 3).map((item, index) => (
                    <div key={index} className="d-flex justify-content-between text-muted">
                      <span>{item.cantidad}x {item.productos?.nombre || item.nombre || 'Producto'}</span>
                      <span>${((item.productos?.precio || item.precio || 0) * item.cantidad).toFixed(2)}</span>
                    </div>
                  ))}
                  {cart.length > 3 && (
                    <div className="text-center mt-1">
                      <span className="text-primary">Y {cart.length - 3} más...</span>
                    </div>
                  )}
                </div>
              </Card.Body>
            </Card>
          )}
        
          <Card className="border-0 shadow-sm mb-4">
            <Card.Body>
              <h5 className="mb-4">Selecciona un método de pago</h5>
              <SelectorMetodoPago 
                onSelectMethod={handleSelectPaymentMethod}
                selectedMethod={paymentMethod}
                total={total}
              />
            </Card.Body>
          </Card>
          
          <div className="d-flex justify-content-between mt-4">
            <Button 
              variant="outline-secondary" 
              onClick={directCheckout ? onCancel : handleGoBackToResume}
            >
              <i className="fas fa-arrow-left me-2"></i>
              {directCheckout ? 'Cancelar' : 'Volver'}
            </Button>
            
            <Button 
              variant="primary" 
              onClick={handleSubmitPayment}
              disabled={!paymentMethod || !validatePaymentDetails()}
            >
              Confirmar pago
              <i className="fas fa-check ms-2"></i>
            </Button>
          </div>
        </div>
      )}

      <Modal 
        show={showReceiptModal} 
        onHide={handleCloseReceipt}
        size="lg"
        centered
      >
        <Modal.Header closeButton>
          <Modal.Title>
            <i className="fas fa-receipt me-2"></i>
            Venta Completada
            {receipt?.offlineMode && (
              <Badge bg="warning" className="ms-2">Offline</Badge>
            )}
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          {receipt && (
            <div className="receipt">
              {receipt.offlineMode && (
                <Alert variant="warning" className="mb-3">
                  <i className="fas fa-wifi-slash me-2"></i>
                  Esta venta se procesó en modo offline y se sincronizará cuando haya conexión.
                </Alert>
              )}
              
              <h5 className="text-center mb-4">Comprobante de Venta</h5>
              
              <div className="receipt-details mb-4">
                <div className="row">
                  <div className="col-6">
                    <p><strong>Folio:</strong> {receipt.id}</p>
                    <p><strong>Fecha:</strong> {new Date(receipt.fecha).toLocaleString()}</p>
                  </div>
                  <div className="col-6 text-end">
                    <p><strong>Vendedor:</strong> {receipt.usuarioNombre || 'N/A'}</p>
                    <p><strong>Método de pago:</strong> {receipt.metodoPago}</p>
                  </div>
                </div>
              </div>
              
              <table className="table table-bordered">
                <thead>
                  <tr>
                    <th>Producto</th>
                    <th className="text-center">Cantidad</th>
                    <th className="text-end">Precio</th>
                    <th className="text-end">Subtotal</th>
                  </tr>
                </thead>
                <tbody>
                  {receipt.productos.map((producto, index) => (
                    <tr key={index}>
                      <td>{producto.nombre || `Producto #${producto.id || producto.producto_id}`}</td>
                      <td className="text-center">{producto.cantidad}</td>
                      <td className="text-end">${typeof producto.precio === 'number' ? producto.precio.toFixed(2) : '0.00'}</td>
                      <td className="text-end">${typeof producto.precio === 'number' && typeof producto.cantidad === 'number' ? 
                        (producto.precio * producto.cantidad).toFixed(2) : '0.00'}</td>
                    </tr>
                  ))}
                </tbody>
                <tfoot>
                  <tr>
                    <td colSpan="3" className="text-end"><strong>Subtotal:</strong></td>
                    <td className="text-end">${typeof receipt.subtotal === 'number' ? receipt.subtotal.toFixed(2) : '0.00'}</td>
                  </tr>
                  {receipt.descuento > 0 && (
                    <tr>
                      <td colSpan="3" className="text-end"><strong>Descuento:</strong></td>
                      <td className="text-end">-${typeof receipt.descuento === 'number' ? receipt.descuento.toFixed(2) : '0.00'}</td>
                    </tr>
                  )}
                  <tr>
                    <td colSpan="3" className="text-end"><strong>Total:</strong></td>
                    <td className="text-end fw-bold">${typeof receipt.total === 'number' ? receipt.total.toFixed(2) : '0.00'}</td>
                  </tr>
                </tfoot>
              </table>
              
              <div className="payment-details mt-4 p-3 bg-light rounded">
                <h6>Detalles del pago:</h6>
                {receipt.metodoPago === 'efectivo' && receipt.detallesPago && (
                  <div>
                    <p><strong>Monto recibido:</strong> ${receipt.detallesPago.amount || '0.00'}</p>
                    <p><strong>Cambio:</strong> ${typeof receipt.detallesPago.change === 'number' ? 
                      receipt.detallesPago.change.toFixed(2) : '0.00'}</p>
                  </div>
                )}
                
                {receipt.metodoPago === 'tarjeta' && receipt.detallesPago && (
                  <div>
                    <p><strong>Referencia:</strong> {receipt.detallesPago.reference || 'No disponible'}</p>
                    <p><strong>Tarjeta:</strong> XXXX-XXXX-XXXX-{receipt.detallesPago.cardDigits || '****'}</p>
                  </div>
                )}
                
                {receipt.metodoPago === 'transferencia' && receipt.detallesPago && (
                  <div>
                    <p><strong>Referencia:</strong> {receipt.detallesPago.reference || 'No disponible'}</p>
                  </div>
                )}
                
                {receipt.metodoPago === 'credito' && receipt.detallesPago && (
                  <div>
                    <p><strong>Cliente:</strong> {receipt.detallesPago.clientName || 'No especificado'}</p>
                    <p><strong>ID/Documento:</strong> {receipt.detallesPago.clientId || 'No especificado'}</p>
                    <p><strong>Monto pendiente:</strong> ${typeof receipt.detallesPago.dueAmount === 'number' ? 
                      receipt.detallesPago.dueAmount.toFixed(2) : receipt.total.toFixed(2)}</p>
                    {receipt.detallesPago.note && (
                      <p><strong>Nota:</strong> {receipt.detallesPago.note}</p>
                    )}
                  </div>
                )}
                
                {receipt.metodoPago === 'mixto' && receipt.detallesPago && receipt.detallesPago.mixedPayments && (
                  <div>
                    <p><strong>Métodos combinados:</strong></p>
                    <ul>
                      {receipt.detallesPago.mixedPayments.map((payment, idx) => (
                        <li key={idx}>
                          {payment.methodId || 'Método desconocido'}: ${typeof payment.amount === 'number' ? 
                            payment.amount.toFixed(2) : parseFloat(payment.amount || 0).toFixed(2)}
                        </li>
                      ))}
                    </ul>
                    {receipt.detallesPago.note && (
                      <p><strong>Nota:</strong> {receipt.detallesPago.note}</p>
                    )}
                  </div>
                )}
              </div>
              
              <div className="mt-4 text-center">
                <p className="mb-0">¡Gracias por su compra!</p>
              </div>
            </div>
          )}
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={handleCloseReceipt}>
            Cerrar
          </Button>
          <Button variant="primary" onClick={() => window.print()}>
            <i className="fas fa-print me-2"></i>
            Imprimir
          </Button>
        </Modal.Footer>
      </Modal>

      <style jsx>{`
        .step-item {
          display: flex;
          flex-direction: column;
          align-items: center;
          z-index: 1;
        }
        
        .step-circle {
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background-color: #e9ecef;
          display: flex;
          align-items: center;
          justify-content: center;
          margin-bottom: 8px;
          font-weight: bold;
          transition: background-color 0.3s;
        }
        
        .step-item.active .step-circle {
          background-color: #8c5cf2;
          color: white;
        }
        
        .step-label {
          font-size: 14px;
          color: #6c757d;
          transition: color 0.3s;
        }
        
        .step-item.active .step-label {
          color: #343a40;
          font-weight: 500;
        }
        
        .step-connector {
          flex-grow: 1;
          height: 3px;
          background-color: #e9ecef;
          margin: 0 8px;
          margin-top: 20px;
          transition: background-color 0.3s;
        }
        
        .step-connector.active {
          background-color: #8c5cf2;
        }
        
        @media print {
          .modal-header, .modal-footer, .alert {
            display: none !important;
          }
          
          body * {
            visibility: hidden;
          }
          
          .modal-body, .modal-body * {
            visibility: visible;
          }
          
          .modal-body {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
          }
        }
      `}</style>
    </div>
  );
};

export default Pagos;