import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, ListGroup, Badge, Row, Col, Form, Spinner, Alert, InputGroup, Container, Modal } from 'react-bootstrap';
import { Link } from 'react-router-dom';
import ItemCarrito from './ItemCarrito';

// Use environment variable for API URL
const API_BASE_URL = 'https://karmaapi-z51n.onrender.com';
const API_URL = `${API_BASE_URL}/api`;

const Carrito = ({ usuario, onCheckout, onRefreshCart }) => {
  const [productosCarrito, setProductosCarrito] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [total, setTotal] = useState(0);
  const [subtotal, setSubtotal] = useState(0);
  const [descuento, setDescuento] = useState(0);
  const [codigoDescuento, setCodigoDescuento] = useState('');
  const [showConfirmClear, setShowConfirmClear] = useState(false);
  const [loadingItems, setLoadingItems] = useState({});
  const [lastUpdate, setLastUpdate] = useState(Date.now());
  const [pendingSync, setPendingSync] = useState(false);
  const [offlineMode, setOfflineMode] = useState(!navigator.onLine);

  useEffect(() => {
    const handleOnline = () => {
      setOfflineMode(false);
      if (pendingSync) {
        sincronizarCambiosPendientes();
      }
    };
    const handleOffline = () => setOfflineMode(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, [pendingSync]);

  useEffect(() => {
    cargarCarrito();
  }, []);

  const calculatedSubtotal = useMemo(() => {
    return productosCarrito.reduce((suma, item) => {
      return suma + (item.productos?.precio || item.precio || 0) * item.cantidad;
    }, 0);
  }, [productosCarrito]);

  useEffect(() => {
    setSubtotal(calculatedSubtotal);
    const nuevoTotal = calculatedSubtotal - descuento;
    setTotal(nuevoTotal);
  }, [calculatedSubtotal, descuento]);

  const cargarCarrito = async (forceRefresh = false) => {
    try {
      const ahora = Date.now();
      const ultimaActualizacion = ahora - lastUpdate;

      if (!forceRefresh && productosCarrito.length > 0 && ultimaActualizacion < 30000) {
        console.log("Usando datos de carrito en memoria");
        return;
      }

      setLoading(true);
      setError(null);

      let carritoData = [];

      try {
        if (!offlineMode) {
          const usuarioId = usuario?.id;
          let url = `${API_URL}/carrito`;

          if (usuarioId) {
            console.log(`Intentando obtener carrito específico para usuario ${usuarioId}`);
            try {
              const specificResponse = await fetch(`${API_URL}/carrito/usuario/${usuarioId}`, {
                method: 'GET',
                headers: {
                  'Accept': 'application/json',
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${usuario?.token || ''}`
                },
                signal: AbortSignal.timeout(8000)
              });

              if (specificResponse.ok) {
                const data = await specificResponse.json();
                carritoData = Array.isArray(data.items) ? data.items : (Array.isArray(data) ? data : []);
                console.log("Carrito específico obtenido con éxito");
              } else {
                throw new Error("Endpoint específico falló");
              }
            } catch (specificError) {
              console.warn("Error con endpoint específico:", specificError.message);
              const response = await fetch(url, {
                method: 'GET',
                headers: {
                  'Accept': 'application/json',
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${usuario?.token || ''}`
                },
                signal: AbortSignal.timeout(8000)
              });

              if (response.ok) {
                const data = await response.json();
                carritoData = Array.isArray(data.items) ? data.items : (Array.isArray(data) ? data : []);
                console.log("Carrito general obtenido con éxito");
              } else {
                throw new Error(`Error en endpoint general: ${response.status}`);
              }
            }

            if (carritoData.length > 0) {
              try {
                localStorage.setItem('carritoCache', JSON.stringify(carritoData));
                localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
              } catch (storageErr) {
                console.warn("No se pudo guardar en caché:", storageErr);
              }
            }
          } else {
            const response = await fetch(url, {
              method: 'GET',
              headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json'
              },
              signal: AbortSignal.timeout(8000)
            });

            if (response.ok) {
              const data = await response.json();
              carritoData = Array.isArray(data.items) ? data.items : (Array.isArray(data) ? data : []);
              console.log("Carrito general obtenido con éxito (sin usuario)");

              try {
                localStorage.setItem('carritoCache', JSON.stringify(carritoData));
                localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
              } catch (storageErr) {}
            } else {
              throw new Error(`Error en endpoint general: ${response.status}`);
            }
          }
        } else {
          throw new Error("Modo offline activo");
        }
      } catch (networkErr) {
        console.warn("Error de red, usando caché:", networkErr.message);
        try {
          const cachedCart = localStorage.getItem('carritoCache');
          if (cachedCart) {
            carritoData = JSON.parse(cachedCart);
            console.log("Usando carrito desde caché local");
          }
        } catch (cacheErr) {
          console.error("Error al recuperar caché:", cacheErr);
        }
      }

      const datosNormalizados = carritoData.map(item => ({
        id: item.id || item.producto_id,
        producto_id: item.producto_id || item.id,
        cantidad: item.cantidad || 1,
        precio: item.precio || item.productos?.precio || 0,
        nombre: item.nombre || item.productos?.nombre || 'Producto',
        productos: item.productos || {
          id: item.producto_id || item.id,
          precio: item.precio || 0,
          nombre: item.nombre || 'Producto'
        }
      }));

      setProductosCarrito(datosNormalizados);
      setLastUpdate(Date.now());
      setLoading(false);
      if (onRefreshCart) onRefreshCart();
    } catch (err) {
      console.error('Error general cargar carrito:', err);
      setError('No se pudo cargar el carrito. Intenta de nuevo más tarde.');

      try {
        const cachedCart = localStorage.getItem('carritoCache');
        if (cachedCart) {
          const carritoData = JSON.parse(cachedCart);
          setProductosCarrito(carritoData);
          console.log("Usando caché como último recurso");
        }
      } catch (e) {}

      setLoading(false);
    }
  };

  const manejarActualizarCantidad = async (itemId, nuevaCantidad) => {
    try {
      if (nuevaCantidad <= 0) {
        return await manejarEliminarProducto(itemId);
      }

      setLoadingItems(prev => ({ ...prev, [itemId]: true }));

      const itemIndex = productosCarrito.findIndex(item => item.id === itemId);
      if (itemIndex === -1) return;

      const updatedCart = [...productosCarrito];
      updatedCart[itemIndex] = {
        ...updatedCart[itemIndex],
        cantidad: nuevaCantidad,
      };

      setProductosCarrito(updatedCart);

      try {
        localStorage.setItem('carritoCache', JSON.stringify(updatedCart));
        localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
      } catch (storageErr) {}

      if (offlineMode) {
        try {
          const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
          pendingChanges.push({
            type: 'update',
            itemId,
            cantidad: nuevaCantidad,
            timestamp: Date.now()
          });
          localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
          setPendingSync(true);
          setLoadingItems(prev => ({ ...prev, [itemId]: false }));
          return;
        } catch (storageErr) {
          console.warn("Error guardando cambios pendientes:", storageErr);
        }
      }

      const response = await fetch(`${API_URL}/carrito/${itemId}/cantidad`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario?.token || ''}`
        },
        body: JSON.stringify({ cantidad: nuevaCantidad }),
        signal: AbortSignal.timeout(5000)
      });

      if (!response.ok) {
        console.warn(`Error al actualizar cantidad en servidor: ${response.status}`);
        const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
        pendingChanges.push({
          type: 'update',
          itemId,
          cantidad: nuevaCantidad,
          timestamp: Date.now()
        });
        localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
        setPendingSync(true);
      }
    } catch (err) {
      console.error('Error actualizando cantidad:', err);
      setPendingSync(true);
    } finally {
      setLoadingItems(prev => ({ ...prev, [itemId]: false }));
    }
  };

  const manejarEliminarProducto = async (itemId) => {
    try {
      setLoadingItems(prev => ({ ...prev, [itemId]: true }));

      const updatedCart = productosCarrito.filter(item => item.id !== itemId);
      setProductosCarrito(updatedCart);

      try {
        localStorage.setItem('carritoCache', JSON.stringify(updatedCart));
        localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
      } catch (e) {}

      if (offlineMode) {
        try {
          const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
          pendingChanges.push({
            type: 'delete',
            itemId,
            timestamp: Date.now()
          });
          localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
          setPendingSync(true);
          return;
        } catch (storageErr) {
          console.warn("Error guardando eliminación pendiente:", storageErr);
        }
      }

      const response = await fetch(`${API_URL}/carrito/${itemId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario?.token || ''}`
        },
        signal: AbortSignal.timeout(5000)
      });

      if (!response.ok) {
        console.warn(`Error eliminando producto del servidor: ${response.status}`);
        const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
        pendingChanges.push({
          type: 'delete',
          itemId,
          timestamp: Date.now()
        });
        localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
        setPendingSync(true);
      }
    } catch (err) {
      console.error('Error eliminando producto:', err);
      setPendingSync(true);
    } finally {
      setLoadingItems(prev => ({ ...prev, [itemId]: false }));
    }
  };

  const manejarVaciarCarrito = async () => {
    try {
      setProductosCarrito([]);

      try {
        localStorage.removeItem('carritoCache');
        localStorage.removeItem('carritoCacheTimestamp');
      } catch (e) {}

      if (offlineMode) {
        try {
          const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
          pendingChanges.push({
            type: 'clear',
            timestamp: Date.now()
          });
          localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
          setPendingSync(true);
          return;
        } catch (e) {}
      }

      const response = await fetch(`${API_URL}/carrito/vaciar`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario?.token || ''}`
        },
        signal: AbortSignal.timeout(5000)
      });

      if (!response.ok) {
        console.warn(`Error al vaciar carrito en servidor: ${response.status}`);
        try {
          const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');
          pendingChanges.push({
            type: 'clear',
            timestamp: Date.now()
          });
          localStorage.setItem('carritoPendingChanges', JSON.stringify(pendingChanges));
          setPendingSync(true);
        } catch (e) {}
      }
    } catch (err) {
      console.error('Error vaciando carrito:', err);
      setPendingSync(true);
    }
  };

  const sincronizarCambiosPendientes = async () => {
    if (offlineMode) {
      console.log("Modo offline, no se pueden sincronizar cambios");
      return;
    }

    try {
      const pendingChanges = JSON.parse(localStorage.getItem('carritoPendingChanges') || '[]');

      if (pendingChanges.length === 0) {
        setPendingSync(false);
        return;
      }

      console.log(`Sincronizando ${pendingChanges.length} cambios pendientes...`);

      let cambiosSincronizados = 0;

      for (const cambio of pendingChanges) {
        try {
          if (cambio.type === 'update') {
            const response = await fetch(`${API_URL}/carrito/${cambio.itemId}/cantidad`, {
              method: 'PUT',
              headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${usuario?.token || ''}`
              },
              body: JSON.stringify({ cantidad: cambio.cantidad }),
              signal: AbortSignal.timeout(5000)
            });

            if (response.ok) cambiosSincronizados++;
          } else if (cambio.type === 'delete') {
            const response = await fetch(`${API_URL}/carrito/${cambio.itemId}`, {
              method: 'DELETE',
              headers: {
                'Authorization': `Bearer ${usuario?.token || ''}`
              },
              signal: AbortSignal.timeout(5000)
            });

            if (response.ok) cambiosSincronizados++;
          } else if (cambio.type === 'clear') {
            const response = await fetch(`${API_URL}/carrito/vaciar`, {
              method: 'DELETE',
              headers: {
                'Authorization': `Bearer ${usuario?.token || ''}`
              },
              signal: AbortSignal.timeout(5000)
            });

            if (response.ok) cambiosSincronizados++;
          }
        } catch (syncError) {
          console.warn(`Error sincronizando cambio: ${syncError.message}`);
        }
      }

      console.log(`Sincronizados ${cambiosSincronizados} de ${pendingChanges.length} cambios`);

      if (cambiosSincronizados === pendingChanges.length) {
        localStorage.removeItem('carritoPendingChanges');
        setPendingSync(false);
        setSuccess('Cambios sincronizados correctamente');
        setTimeout(() => setSuccess(null), 3000);
      } else {
        const cambiosFallidos = pendingChanges.slice(cambiosSincronizados);
        localStorage.setItem('carritoPendingChanges', JSON.stringify(cambiosFallidos));
        setPendingSync(true);
      }

      await cargarCarrito(true);
    } catch (err) {
      console.error('Error sincronizando cambios:', err);
    }
  };

  const manejarProcederPago = () => {
    if (productosCarrito.length === 0) {
      setError('El carrito está vacío');
      return;
    }

    if (pendingSync && !offlineMode) {
      sincronizarCambiosPendientes().then(() => {
        if (onCheckout) {
          onCheckout();
        } else {
          window.location.href = '/checkout';
        }
      });
    } else {
      if (onCheckout) {
        onCheckout();
      } else {
        window.location.href = '/checkout';
      }
    }
  };

  const handleAplicarDescuento = () => {
    if (codigoDescuento === 'PROMO10') {
      setDescuento(10);
      setSuccess('Descuento aplicado correctamente.');
    } else {
      setError('Código promocional inválido.');
    }
  };

  const handleEliminarDescuento = () => {
    setDescuento(0);
    setCodigoDescuento('');
    setSuccess(null);
  };

  const limpiarCarrito = async () => {
    await manejarVaciarCarrito();
    setShowConfirmClear(false);
  };

  const MobileItemsList = () => (
    <div className="d-md-none">
      {productosCarrito.map(item => (
        <div key={item.id} className="mobile-card bg-white mb-3">
          <div className="d-flex justify-content-between align-items-start mb-3">
            <div className="mobile-title">{item.nombre}</div>
            <div className="mobile-price">${parseFloat(item.precio * item.cantidad).toFixed(2)}</div>
          </div>

          <div className="d-flex justify-content-between align-items-center">
            <div className="d-flex align-items-center">
              <button
                className="btn btn-light btn-sm me-2"
                onClick={() => manejarActualizarCantidad(item.id, Math.max(1, item.cantidad - 1))}
              >
                <i className="fas fa-minus"></i>
              </button>
              <div className="border px-3 py-1 rounded">{item.cantidad}</div>
              <button
                className="btn btn-light btn-sm ms-2"
                onClick={() => manejarActualizarCantidad(item.id, item.cantidad + 1)}
              >
                <i className="fas fa-plus"></i>
              </button>
            </div>

            <button
              className="btn btn-link text-danger p-0 border-0"
              onClick={() => manejarEliminarProducto(item.id)}
              aria-label="Eliminar producto"
            >
              <i className="fas fa-trash-alt"></i>
            </button>
          </div>

          <div className="text-muted mt-2 small">
            Precio unitario: ${parseFloat(item.precio).toFixed(2)}
          </div>
        </div>
      ))}

      {productosCarrito.length === 0 && (
        <div className="text-center py-4">
          <i className="fas fa-shopping-cart fa-3x mb-3 text-muted"></i>
          <p>Tu carrito está vacío</p>
          <Link
            to="/productos"
            className="btn btn-primary mt-2"
            style={{ backgroundColor: '#8c5cf2', borderColor: '#7647eb' }}
          >
            Ver productos
          </Link>
        </div>
      )}
    </div>
  );

  const MobileActionBar = () => (
    <div className="mobile-action-bar d-md-none">
      <div>
        <div className="fw-bold fs-5">${total.toFixed(2)}</div>
        <small className="text-muted">{productosCarrito.length} producto(s)</small>
      </div>
      <Button
        variant="primary"
        onClick={manejarProcederPago}
        style={{ backgroundColor: '#8c5cf2', borderColor: '#7647eb' }}
        className="px-4 py-2"
        disabled={productosCarrito.length === 0}
      >
        <i className="fas fa-check me-2"></i>
        Proceder al pago
      </Button>
    </div>
  );

  const MobilePromotions = () => (
    <div className="d-md-none mb-3">
      <div className="mobile-card bg-white mb-3">
        <h5 className="mb-3">Código promocional</h5>
        <div className="input-group mb-2">
          <Form.Control
            type="text"
            placeholder="Ingresa tu código"
            value={codigoDescuento}
            onChange={(e) => setCodigoDescuento(e.target.value)}
          />
          <Button
            variant={descuento > 0 ? 'danger' : 'primary'}
            onClick={descuento > 0 ? handleEliminarDescuento : handleAplicarDescuento}
            disabled={descuento > 0 ? false : !codigoDescuento}
            style={{
              backgroundColor: descuento > 0 ? '#dc3545' : '#8c5cf2',
              borderColor: descuento > 0 ? '#dc3545' : '#7647eb',
            }}
          >
            {descuento > 0 ? 'Eliminar' : 'Aplicar'}
          </Button>
        </div>
        {descuento > 0 && (
          <div className="alert alert-success py-2 mb-0">
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <i className="fas fa-check-circle me-2"></i>
                Descuento aplicado:
              </div>
              <div className="fw-bold text-success">-${descuento.toFixed(2)}</div>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  return (
    <Container className="py-4">
      <div className="mb-4 d-flex justify-content-between align-items-center">
        <h2 className="rubik-medium mb-0">
          <i className="fas fa-shopping-cart me-2" style={{ color: '#8c5cf2' }}></i>
          Carrito de Compra
        </h2>
        <div>
          {productosCarrito.length > 0 && (
            <Button
              variant="outline-danger"
              className="d-none d-md-inline-block"
              onClick={() => setShowConfirmClear(true)}
              size="sm"
            >
              <i className="fas fa-trash-alt me-2"></i>
              Limpiar carrito
            </Button>
          )}
        </div>
      </div>

      {error && (
        <Alert variant="danger" dismissible onClose={() => setError(null)}>
          <i className="fas fa-exclamation-circle me-2"></i>
          {error}
        </Alert>
      )}

      {success && (
        <Alert variant="success" dismissible onClose={() => setSuccess(null)}>
          <i className="fas fa-check-circle me-2"></i>
          {success}
        </Alert>
      )}

      {loading ? (
        <div className="text-center py-5">
          <Spinner animation="border" role="status" style={{ color: '#8c5cf2' }}>
            <span className="visually-hidden">Cargando...</span>
          </Spinner>
          <p className="mt-3 text-muted">Cargando el carrito...</p>
        </div>
      ) : (
        <Row>
          <Col lg={8}>
            <Card className="border-0 shadow-sm mb-4">
              <Card.Header className="bg-white py-3 border-0">
                <div className="d-flex justify-content-between align-items-center">
                  <h5 className="mb-0">
                    <i className="fas fa-box me-2" style={{ color: '#8c5cf2' }}></i>
                    Productos
                    <span
                      className="badge rounded-pill ms-2"
                      style={{ backgroundColor: '#f5f5f7', color: '#555' }}
                    >
                      {productosCarrito.length}
                    </span>
                  </h5>
                  {productosCarrito.length > 0 && (
                    <Button
                      variant="outline-danger"
                      className="d-md-none"
                      onClick={() => setShowConfirmClear(true)}
                      size="sm"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </Button>
                  )}
                </div>
              </Card.Header>
              <Card.Body className="p-0">
                <div className="d-none d-md-block">
                  <ListGroup variant="flush">
                    {productosCarrito.map(item => (
                      <ItemCarrito
                        key={item.id}
                        item={item}
                        onUpdateQuantity={manejarActualizarCantidad}
                        onRemove={manejarEliminarProducto}
                      />
                    ))}
                  </ListGroup>
                </div>

                <MobileItemsList />

                {productosCarrito.length === 0 && (
                  <div className="text-center py-5 d-none d-md-block">
                    <i className="fas fa-shopping-cart fa-4x mb-3 text-muted"></i>
                    <h5>Tu carrito está vacío</h5>
                    <p className="text-muted">Agrega productos para continuar</p>
                    <Link
                      to="/productos"
                      className="btn btn-primary mt-2"
                      style={{ backgroundColor: '#8c5cf2', borderColor: '#7647eb' }}
                    >
                      Ver productos
                    </Link>
                  </div>
                )}
              </Card.Body>
            </Card>

            <MobilePromotions />
          </Col>
          <Col lg={4}>
            <Card className="border-0 shadow-sm mb-4">
              <Card.Header className="bg-white py-3 border-0">
                <h5 className="mb-0">
                  <i className="fas fa-receipt me-2" style={{ color: '#8c5cf2' }}></i>
                  Resumen del pedido
                </h5>
              </Card.Header>
              <Card.Body>
                <div className="d-flex justify-content-between mb-2">
                  <span>Subtotal</span>
                  <span>${subtotal.toFixed(2)}</span>
                </div>

                {descuento > 0 && (
                  <div className="d-flex justify-content-between mb-2 text-danger">
                    <span>Descuento</span>
                    <span>-${descuento.toFixed(2)}</span>
                  </div>
                )}

                <hr />

                <div className="d-flex justify-content-between mb-3">
                  <span className="fw-bold">Total</span>
                  <span className="fw-bold fs-5">${total.toFixed(2)}</span>
                </div>

                <Button
                  variant="primary"
                  className="w-100 mb-3"
                  disabled={productosCarrito.length === 0}
                  onClick={manejarProcederPago}
                  style={{ backgroundColor: '#8c5cf2', borderColor: '#7647eb' }}
                >
                  <i className="fas fa-check me-2"></i>
                  Proceder al pago
                </Button>

                <Link to="/productos" className="btn btn-outline-secondary w-100">
                  <i className="fas fa-arrow-left me-2"></i>
                  Seguir comprando
                </Link>
              </Card.Body>
            </Card>

            <Card className="border-0 shadow-sm d-none d-md-block">
              <Card.Header className="bg-white py-3 border-0">
                <h5 className="mb-0">
                  <i className="fas fa-tags me-2" style={{ color: '#8c5cf2' }}></i>
                  Código promocional
                </h5>
              </Card.Header>
              <Card.Body>
                <div className="input-group mb-3">
                  <Form.Control
                    type="text"
                    placeholder="Ingresa tu código"
                    value={codigoDescuento}
                    onChange={(e) => setCodigoDescuento(e.target.value)}
                  />
                  <Button
                    variant={descuento > 0 ? 'danger' : 'primary'}
                    onClick={descuento > 0 ? handleEliminarDescuento : handleAplicarDescuento}
                    disabled={descuento > 0 ? false : !codigoDescuento}
                    style={{
                      backgroundColor: descuento > 0 ? '#dc3545' : '#8c5cf2',
                      borderColor: descuento > 0 ? '#dc3545' : '#7647eb',
                    }}
                  >
                    {descuento > 0 ? 'Eliminar' : 'Aplicar'}
                  </Button>
                </div>

                {descuento > 0 && (
                  <Alert variant="success" className="mb-0 d-flex justify-content-between align-items-center">
                    <div>
                      <i className="fas fa-check-circle me-2"></i>
                      Descuento aplicado
                    </div>
                    <strong>-${descuento.toFixed(2)}</strong>
                  </Alert>
                )}

                <div className="mt-3">
                  <small className="text-muted">
                    <i className="fas fa-info-circle me-1"></i>
                    Los códigos promocionales se aplican al subtotal
                  </small>
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      )}

      {!loading && productosCarrito.length > 0 && <MobileActionBar />}

      <Modal show={showConfirmClear} onHide={() => setShowConfirmClear(false)} centered>
        <Modal.Header closeButton>
          <Modal.Title>Confirmar acción</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <p>¿Estás seguro de que deseas eliminar todos los productos del carrito?</p>
          <p className="mb-0 text-muted">Esta acción no se puede deshacer.</p>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="outline-secondary" onClick={() => setShowConfirmClear(false)}>
            Cancelar
          </Button>
          <Button variant="danger" onClick={limpiarCarrito}>
            Eliminar todo
          </Button>
        </Modal.Footer>
      </Modal>
    </Container>
  );
};

export default Carrito;
