import React, { useState, useEffect } from "react";
import { Container } from 'react-bootstrap';
import { BrowserRouter as Router } from "react-router-dom";
import Login from "./components/Login";
import Productos from "./components/Productos";
import Carrito from "./components/Carrito";
import Pagos from "./components/Pagos";
import Ventas from "./components/Ventas";
import Dashboard from "./components/dashboard/Dashboard"; // Importar el nuevo componente Dashboard
import GeneradorEtiquetas from "./components/etiquetas/GeneradorEtiquetas";
import 'bootstrap/dist/css/bootstrap.min.css';

// Import our components
import ErrorBoundary from "./components/seguridad/ErrorBoundary";
import PermissionGuard from "./components/seguridad/PermissionGuard";
import Layout from "./components/layout/Layout";
import { logoutUsuario } from "./servicios/api";

// Use environment variable for API URL
const API_URL = 'https://karmaapi-z51n.onrender.com';

function App() {
  const [user, setUser] = useState(null);
  const [currentPage, setCurrentPage] = useState('inicio');
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const [carrito, setCarrito] = useState([]);
  const [offlineMode, setOfflineMode] = useState(!navigator.onLine);
  const [directCheckout, setDirectCheckout] = useState(false); // Nuevo estado para controlar el pago directo
  
  // Verificar si hay un usuario guardado en localStorage al iniciar
  useEffect(() => {
    const storedUser = localStorage.getItem('karmaUser');
    
    // Escuchar eventos de conexión
    const handleOnline = () => setOfflineMode(false);
    const handleOffline = () => setOfflineMode(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    if (storedUser) {
      try {
        const parsedUser = JSON.parse(storedUser);
        
        // Verificar que el usuario tenga todos los campos necesarios
        if (parsedUser && (parsedUser.rol || parsedUser.role) && parsedUser.nombre && parsedUser.token) {
          // Asegurar que el campo rol existe (podría venir como 'role' desde la API)
          if (!parsedUser.rol && parsedUser.role) {
            parsedUser.rol = parsedUser.role;
          }
          setUser(parsedUser);
        } else {
          // Si no tiene todos los campos necesarios, forzar inicio de sesión
          localStorage.removeItem('karmaUser');
          setUser(null);
        }
      } catch (error) {
        console.error("Error parsing stored user:", error);
        localStorage.removeItem('karmaUser');
        setUser(null);
      }
    }
    
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // When user changes, fetch cart and store user in localStorage
  useEffect(() => {
    if (user) {
      localStorage.setItem('karmaUser', JSON.stringify(user));
      // Solo intentar obtener el carrito si estamos online
      if (navigator.onLine) {
        fetchCarrito();
      }
    } else {
      localStorage.removeItem('karmaUser');
    }
  }, [user]);

  const fetchCarrito = async () => {
    if (!user || offlineMode) return;
    
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 8000); // 8 segundos timeout
      
      // Intentar primero con el endpoint específico de usuario
      try {
        console.log(`Intentando obtener carrito del usuario ${user.id}...`);
        const response = await fetch(`${API_URL}/api/carrito/usuario/${user.id}`, {
          signal: controller.signal,
          headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${user.token || 'no-token'}`
          }
        });
        
        if (response.ok) {
          const data = await response.json();
          console.log(`Carrito obtenido exitosamente para usuario ${user.id}:`, data);
          setCarrito(data?.items || []);
          clearTimeout(timeoutId);
          return;
        } else {
          console.warn(`Error en respuesta del carrito específico: ${response.status}. Intentando endpoint general...`);
        }
      } catch (userCartError) {
        console.warn(`Excepción al obtener carrito de usuario: ${userCartError.message}. Intentando endpoint general...`);
      }
      
      // Si el endpoint específico falla, intentar con el endpoint general
      const generalResponse = await fetch(`${API_URL}/api/carrito`, {
        signal: controller.signal,
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${user.token || 'no-token'}`
        }
      });
      
      clearTimeout(timeoutId);
      
      if (!generalResponse.ok) {
        console.error(`Error en respuesta del carrito general: ${generalResponse.status} - ${generalResponse.statusText}`);
        // Si el servidor devuelve 404, asumimos que el carrito está vacío
        if (generalResponse.status === 404) {
          console.log("El carrito no existe, estableciendo carrito vacío");
          setCarrito([]);
        }
        return;
      }
      
      const generalData = await generalResponse.json();
      console.log("Carrito obtenido del endpoint general:", generalData);
      setCarrito(generalData?.items || []);
    } catch (error) {
      if (error.name === 'AbortError') {
        console.error("Timeout al obtener el carrito. La solicitud tardó demasiado.");
      } else {
        console.error("Error detallado al obtener carrito:", error.message, error.stack);
      }
      
      // En caso de error de red, intentar recuperar carrito del localStorage como fallback
      try {
        const cachedCart = localStorage.getItem('carritoCache');
        if (cachedCart) {
          const parsedCart = JSON.parse(cachedCart);
          console.log("Usando carrito en caché del localStorage:", parsedCart);
          setCarrito(parsedCart);
        }
      } catch (cacheError) {
        console.error("Error al recuperar carrito en caché:", cacheError);
      }
    }
  };

  const handleLogin = (userData) => {
    // Verificar que los datos del usuario sean correctos
    if (!userData || !userData.token) {
      console.error("Datos de usuario incorrectos en login");
      return;
    }
    
    // Asegurar que el campo rol existe (podría venir como 'role' desde la API)
    if (!userData.rol && userData.role) {
      userData.rol = userData.role;
    }
    
    // Actualizar estado y localStorage
    setUser(userData);
    localStorage.setItem('karmaUser', JSON.stringify(userData));
    setCurrentPage('inicio');
  };

  const handleLogout = async () => {
    // Limpieza completa de la sesión
    try {
      // Intentar cerrar sesión en la API (si está disponible)
      if (navigator.onLine && user && user.token) {
        await logoutUsuario(user.token);
      }

      // Limpiar completamente el estado de la aplicación
      setCarrito([]);
      setCurrentPage('inicio');
      
      // Eliminar sesión del localStorage
      localStorage.removeItem('karmaUser');
      
      // Limpiar el estado del usuario
      setUser(null);
      
      console.log('Sesión cerrada exitosamente');
    } catch (error) {
      console.error('Error durante el cierre de sesión:', error);
      // Forzar el cierre incluso si hay errores
      localStorage.removeItem('karmaUser');
      setUser(null);
    }
  };

  const handleProceedToCheckout = () => {
    setIsCheckingOut(true);
    setDirectCheckout(false);
  };
  
  const handleDirectCheckout = () => {
    // Primero cargar el carrito más reciente
    fetchCarrito().then(() => {
      setIsCheckingOut(true);
      setDirectCheckout(true);
      setCurrentPage('pago-directo');
    });
  };
  
  const handleCompleteCheckout = (orderData) => {
    setIsCheckingOut(false);
    setDirectCheckout(false);
    setCurrentPage('inicio');
    // Clear cart after checkout
    setCarrito([]);
    alert(`¡Compra completada! Número de orden: ${orderData.id}`);
  };
  
  const handleCancelCheckout = () => {
    setIsCheckingOut(false);
    setDirectCheckout(false);
    setCurrentPage('carrito');
  };

  // Si no hay usuario, mostrar login
  if (!user) {
    return <Login onLoginSuccess={handleLogin} />;
  }

  // Define the content for the current page
  const renderContent = () => {
    // If checkout is in progress, show the Pagos component
    if (isCheckingOut) {
      return (
        <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
          <Pagos 
            usuario={user} 
            onCompletePurchase={handleCompleteCheckout}
            onCancel={handleCancelCheckout}
            directCheckout={directCheckout}
          />
        </PermissionGuard>
      );
    }

    // Otherwise, show the requested page
    switch (currentPage) {
      case 'inicio':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <Dashboard />
          </PermissionGuard>
        );
      case 'inventario':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <Productos usuario={user} onRefreshCart={fetchCarrito} />
          </PermissionGuard>
        );
      case 'carrito':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <Carrito 
              usuario={user} 
              onCheckout={handleProceedToCheckout}
              onRefreshCart={fetchCarrito}
            />
          </PermissionGuard>
        );
      case 'pago-directo':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <Pagos 
              usuario={user} 
              onCompletePurchase={handleCompleteCheckout}
              onCancel={handleCancelCheckout}
              directCheckout={true}
            />
          </PermissionGuard>
        );
      case 'ventas':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <Ventas usuario={user} />
          </PermissionGuard>
        );
      case 'etiquetas':
        return (
          <PermissionGuard currentUser={user} requiredRoles={['admin', 'user']}>
            <GeneradorEtiquetas />
          </PermissionGuard>
        );
      default:
        return <div>Página no encontrada</div>;
    }
  };

  // Wrapped with Layout and ErrorBoundary
  return (
    <Router>
      <ErrorBoundary>
        <Layout 
          user={user} 
          onLogout={handleLogout}
          onNavigate={setCurrentPage}
          currentPage={currentPage}
          cartItemCount={carrito.length}
          onDirectCheckout={handleDirectCheckout}
        >
          <Container fluid className="p-0">
            {renderContent()}
          </Container>
        </Layout>
      </ErrorBoundary>
    </Router>
  );
}

export default App;
