import React from 'react';

/**
 * StaticBackground - A lightweight, CSS-only gradient background 
 * that replaces the heavy canvas-based AnimatedBackground component
 * 
 * @param {Object} props - Properties for the component
 * @param {string} props.primaryColor - Primary color (hex)
 * @param {string} props.secondaryColor - Secondary color (hex)
 * @param {string} props.accentColor - Accent color (hex)
 */
const StaticBackground = ({
  primaryColor = '#ff85e4',   // Rosa Karma
  secondaryColor = '#c878b8', // Tono complementario
  accentColor = '#80b3c7',    // Azul complementario
}) => {
  // CSS variables for the gradient
  const style = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    overflow: 'hidden',
    pointerEvents: 'none',
    background: `radial-gradient(circle at 30% 30%, ${primaryColor}10, transparent 60%), 
                radial-gradient(circle at 70% 60%, ${secondaryColor}10, transparent 60%),
                radial-gradient(circle at 50% 50%, ${accentColor}08, transparent 70%),
                linear-gradient(135deg, #f5f7fa 0%, #f1f4f8 100%)`,
  };

  return <div style={style} />;
};

export default StaticBackground;
