// Función mejorada con autenticación robusta y sistema de fallback
export const mostrarCarrito = async (usuarioId) => {
  try {
    // Guardar timestamp para medir tiempo de respuesta
    const startTime = Date.now();
    console.log(`Obteniendo carrito para usuario ${usuarioId}...`);
    
    // Intentar primero con el endpoint específico de usuario
    try {
      const response = await authedFetch(`${API_URL}${API_PREFIX}carrito/usuario/${usuarioId}`, {
        timeout: isMobileDevice() ? 8000 : 10000 // timeout menor para móviles
      });
      
      if (response.ok) {
        const data = await response.json();
        console.log(`Carrito obtenido exitosamente en ${Date.now() - startTime}ms:`, data);
        
        // Guardar en caché para uso offline
        try {
          localStorage.setItem('carritoCache', JSON.stringify(data?.items || []));
          localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
        } catch (cacheError) {
          console.warn("No se pudo guardar el carrito en caché:", cacheError);
        }
        
        return data;
      } else if (response.status === 500) {
        // Puede ser error de cliente_id, intentar con endpoint general
        console.warn("Error 500 al obtener carrito específico. Puede ser problema con cliente_id. Intentando endpoint general...");
      } else {
        console.warn(`Error ${response.status} al obtener carrito específico. Intentando endpoint general...`);
      }
    } catch (specificError) {
      console.warn(`Error al obtener carrito específico: ${specificError.message}. Intentando endpoint general...`);
    }
    
    // Si el endpoint específico falla, intentar con el endpoint general
    try {
      console.log("Usando endpoint general del carrito como fallback...");
      const generalResponse = await authedFetch(`${API_URL}${API_PREFIX}carrito`, {
        timeout: isMobileDevice() ? 5000 : 8000 // timeout menor para el segundo intento
      });
      
      if (generalResponse.ok) {
        const generalData = await generalResponse.json();
        console.log(`Carrito obtenido del endpoint general en ${Date.now() - startTime}ms:`, generalData);
        
        // Guardar en caché para uso offline
        try {
          localStorage.setItem('carritoCache', JSON.stringify(generalData?.items || []));
          localStorage.setItem('carritoCacheTimestamp', Date.now().toString());
        } catch (cacheError) {
          console.warn("No se pudo guardar el carrito general en caché:", cacheError);
        }
        
        return generalData;
      } else {
        console.error(`Endpoint general también falló con error ${generalResponse.status}`);
      }
    } catch (generalError) {
      console.error(`Error al obtener carrito general: ${generalError.message}`);
    }
    
    // Si ambos endpoints fallan, intentar usar la caché
    try {
      const cachedCart = localStorage.getItem('carritoCache');
      const cacheTimestamp = localStorage.getItem('carritoCacheTimestamp');
      
      if (cachedCart) {
        const parsedCart = JSON.parse(cachedCart);
        const cacheAge = cacheTimestamp ? (Date.now() - parseInt(cacheTimestamp)) / 1000 / 60 : 999;
        console.log(`Usando carrito en caché de hace ${cacheAge.toFixed(1)} minutos:`, parsedCart);
        
        return { 
          items: parsedCart, 
          total: parsedCart.reduce((sum, item) => sum + ((item.precio || 0) * (item.cantidad || 1)), 0),
          fromCache: true,
          cacheTime: new Date(parseInt(cacheTimestamp))
        };
      }
    } catch (cacheError) {
      console.error("Error al recuperar carrito en caché:", cacheError);
    }
    
    // Si todo falla, devolver carrito vacío
    console.log("Todos los intentos fallaron. Devolviendo carrito vacío.");
    return { items: [], total: 0, empty: true };
  } catch (error) {
    console.error("Error al mostrar el carrito:", error);
    
    // Intentar usar cache como último recurso
    try {
      const cachedCart = localStorage.getItem('carritoCache');
      if (cachedCart) {
        const parsedCart = JSON.parse(cachedCart);
        console.log("Usando carrito en caché como último recurso:", parsedCart);
        return { 
          items: parsedCart, 
          total: parsedCart.reduce((sum, item) => sum + ((item.precio || 0) * (item.cantidad || 1)), 0),
          fromCache: true,
          emergency: true
        };
      }
    } catch (e) {}
    
    // Realmente todo falló, devolver vacío
    return { items: [], total: 0, error: true };
  }
};

// Función específica para vaciar el carrito
export const vaciarCarrito = async () => {
  try {
    const response = await authedFetch(`${API_URL}${API_PREFIX}carrito/vaciar`, {
      method: 'DELETE'
    });
    
    // Si la API devuelve éxito
    if (response.ok) {
      console.log("Carrito vaciado exitosamente desde la API");
      
      // Limpiar también la caché local
      localStorage.removeItem('carritoCache');
      localStorage.removeItem('carritoCacheTimestamp');
      
      return { success: true, message: "Carrito vaciado correctamente" };
    }
    
    // Si el endpoint específico falla, intentar con un enfoque alternativo
    console.warn(`Error al vaciar carrito con endpoint específico: ${response.status}. Intentando alternativa...`);
    
    // Intentar obtener todos los productos en el carrito y eliminarlos uno por uno
    const carritoResponse = await authedFetch(`${API_URL}${API_PREFIX}carrito`);
    
    if (carritoResponse.ok) {
      const carritoData = await carritoResponse.json();
      const items = carritoData?.items || [];
      
      // Si no hay items, consideramos que ya está vacío
      if (items.length === 0) {
        console.log("El carrito ya está vacío");
        return { success: true, message: "El carrito ya estaba vacío" };
      }
      
      // Obtener el usuario actual
      const storedUser = localStorage.getItem('karmaUser');
      let usuarioId = null;
      
      if (storedUser) {
        try {
          const user = JSON.parse(storedUser);
          usuarioId = user.id;
        } catch (error) {
          console.error("Error al recuperar ID de usuario:", error);
        }
      }
      
      // Si no hay usuario, no podemos continuar
      if (!usuarioId) {
        throw new Error("No se pudo identificar al usuario para vaciar el carrito");
      }
      
      // Eliminar cada producto del carrito
      let productosEliminados = 0;
      
      for (const item of items) {
        const productoId = item.producto_id || item.id;
        try {
          await eliminarCarrito(usuarioId, productoId);
          productosEliminados++;
        } catch (deleteError) {
          console.error(`Error al eliminar producto ${productoId} del carrito:`, deleteError);
        }
      }
      
      // Limpiar caché local
      localStorage.removeItem('carritoCache');
      localStorage.removeItem('carritoCacheTimestamp');
      
      return { 
        success: true, 
        message: `Carrito vaciado usando método alternativo. ${productosEliminados} de ${items.length} productos eliminados.` 
      };
    }
    
    // Si también falla obtener el carrito, intentamos con otra aproximación
    console.warn("También falló obtener el carrito para eliminación manual. Último intento...");
    
    // Limpiar al menos la caché local para que la aplicación muestre carrito vacío
    localStorage.removeItem('carritoCache');
    localStorage.removeItem('carritoCacheTimestamp');
    
    return { 
      success: false, 
      message: "No se pudo vaciar el carrito en el servidor, pero se limpió localmente",
      localOnly: true
    };
    
  } catch (error) {
    console.error("Error al vaciar el carrito:", error);
    
    // En caso de error, al menos limpiar la caché local
    localStorage.removeItem('carritoCache');
    localStorage.removeItem('carritoCacheTimestamp');
    
    return { 
      success: false, 
      error: error.message, 
      localOnly: true,
      message: "Error en el servidor, pero el carrito se limpió localmente"
    };
  }
};

